{
  "_comment": "MCP policy for @metaharness/example-pinecone — default-deny, read/safe Pinecone tools only. ADR-062.",
  "defaultDeny": true,
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 20000,
  "maxToolCallsPerTurn": 12,
  "auditLog": true,
  "auditLogPath": ".harness/audit/mcp-calls.jsonl",
  "mutations_require_flag": "--allow-mutations",
  "_mutations_note": "Upsert, delete, and namespace-drop are NOT in the default grant. Pass --allow-mutations to unlock them; they must also clear requireApprovalForDangerous.",
  "grantedTools": [
    {
      "tool": "pinecone__index_list",
      "reason": "List all indexes in the project — read only"
    },
    {
      "tool": "pinecone__index_describe",
      "reason": "Describe a single index (dimension, metric, host, status) — read only"
    },
    {
      "tool": "pinecone__index_stats",
      "reason": "Fetch namespace vector counts and index fullness — read only"
    },
    {
      "tool": "pinecone__vector_query",
      "reason": "Query vectors by embedding or by ID with top-k, filter, and includeMetadata — read only"
    },
    {
      "tool": "pinecone__vector_fetch",
      "reason": "Fetch specific vectors by ID — read only"
    },
    {
      "tool": "pinecone__namespace_list",
      "reason": "List namespaces within an index — read only"
    }
  ],
  "deniedCapabilities": [
    "pinecone__vector_upsert",
    "pinecone__vector_delete",
    "pinecone__index_create",
    "pinecone__index_delete",
    "pinecone__namespace_delete"
  ]
}
